#include "kernel_operator.h"

class KernelConvTransposed3dAsymmetricInputAsymmetricKernelStridedPaddedGroupedCustom {
public:
    __aicore__ inline KernelConvTransposed3dAsymmetricInputAsymmetricKernelStridedPaddedGroupedCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR y,
                                uint32_t n, uint32_t cin, uint32_t din, uint32_t hin, uint32_t win,
                                uint32_t coutPerG, uint32_t groups,
                                uint32_t kd, uint32_t kh, uint32_t kw,
                                uint32_t sd, uint32_t sh, uint32_t sw,
                                uint32_t pd, uint32_t ph, uint32_t pw,
                                uint32_t opd, uint32_t oph, uint32_t opw,
                                uint32_t dd, uint32_t dh, uint32_t dw,
                                uint32_t dout, uint32_t hout, uint32_t wout)
    {
        n_ = n; cin_ = cin; din_ = din; hin_ = hin; win_ = win;
        coutPerG_ = coutPerG; groups_ = groups;
        kd_ = kd; kh_ = kh; kw_ = kw;
        sd_ = sd; sh_ = sh; sw_ = sw;
        pd_ = pd; ph_ = ph; pw_ = pw;
        opd_ = opd; oph_ = oph; opw_ = opw;
        dd_ = dd; dh_ = dh; dw_ = dw;
        dout_ = dout; hout_ = hout; wout_ = wout;

        // Set GM buffers
        uint64_t xSize = (uint64_t)n_ * cin_ * din_ * hin_ * win_;
        uint64_t wSize = (uint64_t)cin_ * coutPerG_ * kd_ * kh_ * kw_;
        uint64_t ySize = (uint64_t)n_ * (uint32_t)(coutPerG_ * groups_) * dout_ * hout_ * wout_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, xSize);
        wGm_.SetGlobalBuffer((__gm__ float*)w, wSize);
        yGm_.SetGlobalBuffer((__gm__ float*)y, ySize);

        // Init small working buffers (length 1 tensors for scalar math)
        pipe_.InitBuffer(tmpSumQ_, 1, sizeof(float));
        pipe_.InitBuffer(tmpXQ_, 1, sizeof(float));
        pipe_.InitBuffer(tmpWQ_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        const uint32_t cout = coutPerG_ * groups_;
        const uint32_t totalBlocks = n_ * cout;

        const uint32_t blockIdx = (uint32_t)AscendC::GetBlockIdx();
        if (blockIdx >= totalBlocks) return;

        const uint32_t nIdx = blockIdx / cout;
        const uint32_t oc   = blockIdx % cout;
        const uint32_t g    = oc / coutPerG_;
        const uint32_t ocg  = oc % coutPerG_;
        const uint32_t cinPerG = cin_ / groups_;

        // Precompute strides for indexing
        const uint64_t x_stride_w = 1ULL;
        const uint64_t x_stride_h = (uint64_t)win_;
        const uint64_t x_stride_d = (uint64_t)hin_ * win_;
        const uint64_t x_stride_c = (uint64_t)din_ * hin_ * win_;
        const uint64_t x_stride_n = (uint64_t)cin_ * x_stride_c;

        const uint64_t y_stride_w = 1ULL;
        const uint64_t y_stride_h = (uint64_t)wout_;
        const uint64_t y_stride_d = (uint64_t)hout_ * wout_;
        const uint64_t y_stride_c = (uint64_t)dout_ * hout_ * wout_;
        const uint64_t y_stride_n = (uint64_t)(cout) * y_stride_c;

        const uint64_t w_k_total = (uint64_t)kd_ * kh_ * kw_;
        const uint64_t w_stride_kw = 1ULL;
        const uint64_t w_stride_kh = (uint64_t)kw_;
        const uint64_t w_stride_kd = (uint64_t)kh_ * kw_;
        const uint64_t w_stride_ocg = (uint64_t)kd_ * kh_ * kw_;
        const uint64_t w_stride_cin = (uint64_t)coutPerG_ * w_k_total;

        AscendC::LocalTensor<float> sumLocal = tmpSumQ_.AllocTensor<float>();
        AscendC::LocalTensor<float> xLocal1  = tmpXQ_.AllocTensor<float>();
        AscendC::LocalTensor<float> wLocal1  = tmpWQ_.AllocTensor<float>();

        for (uint32_t od = 0; od < dout_; ++od) {
            for (uint32_t oh = 0; oh < hout_; ++oh) {
                for (uint32_t ow = 0; ow < wout_; ++ow) {
                    // Initialize sumLocal to 0
                    AscendC::Dup(sumLocal, 0.0f, 1);

                    // Loop over kernel and input channels for this group
                    for (uint32_t kd = 0; kd < kd_; ++kd) {
                        int64_t tD = (int64_t)od + (int64_t)pd_ - (int64_t)kd * (int64_t)dd_;
                        if (tD < 0) continue;
                        if ((tD % (int64_t)sd_) != 0) continue;
                        int64_t id = tD / (int64_t)sd_;
                        if (id < 0 || id >= (int64_t)din_) continue;

                        for (uint32_t kh = 0; kh < kh_; ++kh) {
                            int64_t tH = (int64_t)oh + (int64_t)ph_ - (int64_t)kh * (int64_t)dh_;
                            if (tH < 0) continue;
                            if ((tH % (int64_t)sh_) != 0) continue;
                            int64_t ih = tH / (int64_t)sh_;
                            if (ih < 0 || ih >= (int64_t)hin_) continue;

                            for (uint32_t kw = 0; kw < kw_; ++kw) {
                                int64_t tW = (int64_t)ow + (int64_t)pw_ - (int64_t)kw * (int64_t)dw_;
                                if (tW < 0) continue;
                                if ((tW % (int64_t)sw_) != 0) continue;
                                int64_t iw = tW / (int64_t)sw_;
                                if (iw < 0 || iw >= (int64_t)win_) continue;

                                // offsets part common for all cin in this group
                                const uint64_t baseX_spatial =
                                    (uint64_t)id * x_stride_d +
                                    (uint64_t)ih * x_stride_h +
                                    (uint64_t)iw * x_stride_w;
                                const uint64_t baseW_k =
                                    (uint64_t)kd * w_stride_kd +
                                    (uint64_t)kh * w_stride_kh +
                                    (uint64_t)kw * w_stride_kw;

                                for (uint32_t icg = 0; icg < cinPerG; ++icg) {
                                    const uint32_t ic_abs = g * cinPerG + icg;

                                    // X offset
                                    const uint64_t x_off =
                                        (uint64_t)nIdx * x_stride_n +
                                        (uint64_t)ic_abs * x_stride_c +
                                        baseX_spatial;

                                    // W offset
                                    const uint64_t w_off =
                                        (uint64_t)ic_abs * w_stride_cin +
                                        (uint64_t)ocg    * w_stride_ocg +
                                        baseW_k;

                                    // Load scalar x and w, accumulate: sum += x * w
                                    AscendC::DataCopy(xLocal1, xGm_[x_off], 1);
                                    AscendC::DataCopy(wLocal1, wGm_[w_off], 1);
                                    AscendC::Mul(xLocal1, xLocal1, wLocal1, 1);
                                    AscendC::Add(sumLocal, sumLocal, xLocal1, 1);
                                } // icg
                            } // kw
                        } // kh
                    } // kd

                    // Write sum to Y
                    const uint64_t y_off =
                        (uint64_t)nIdx * y_stride_n +
                        (uint64_t)oc   * y_stride_c +
                        (uint64_t)od   * y_stride_d +
                        (uint64_t)oh   * y_stride_h +
                        (uint64_t)ow   * y_stride_w;

                    AscendC::DataCopy(yGm_[y_off], sumLocal, 1);
                } // ow
            } // oh
        } // od

        tmpWQ_.FreeTensor(wLocal1);
        tmpXQ_.FreeTensor(xLocal1);
        tmpSumQ_.FreeTensor(sumLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpSumQ_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpXQ_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpWQ_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t n_{0}, cin_{0}, din_{0}, hin_{0}, win_{0};
    uint32_t coutPerG_{0}, groups_{1};
    uint32_t kd_{0}, kh_{0}, kw_{0};
    uint32_t sd_{1}, sh_{1}, sw_{1};
    uint32_t pd_{0}, ph_{0}, pw_{0};
    uint32_t opd_{0}, oph_{0}, opw_{0};
    uint32_t dd_{1}, dh_{1}, dw_{1};
    uint32_t dout_{0}, hout_{0}, wout_{0};
};

