    KernelConvTransposed3dAsymmetricInputAsymmetricKernelStridedPaddedGroupedCustom op;
    op.Init(
        x, weight, y,
        tiling_data.n, tiling_data.cin, tiling_data.din, tiling_data.hin, tiling_data.win,
        tiling_data.coutPerG, tiling_data.groups,
        tiling_data.kd, tiling_data.kh, tiling_data.kw,
        tiling_data.sd, tiling_data.sh, tiling_data.sw,
        tiling_data.pd, tiling_data.ph, tiling_data.pw,
        tiling_data.opd, tiling_data.oph, tiling_data.opw,
        tiling_data.dd, tiling_data.dh, tiling_data.dw,
        tiling_data.dout, tiling_data.hout, tiling_data.wout
    );
    op.Process();
}
